import { TalksClient } from "./packages/talks";
import { ClipsClient } from "./packages/clips";
/**
 * D-ID SDK client
 */
export default class DidClient {
    /**
     * D-ID client configuration
     */
    private config;
    /**
     * D-ID talks client. Used to interact with the talks API.
     */
    private talksClient;
    /**
     * D-ID clips client. Used to interact with the clips API.
     */
    private clipsClient;
    /**
     * @param configuration - D-ID sdk client configuration object
     */
    constructor(apiKey: string, basePath?: string);
    /**
     * Get access to the talks client api wrapper
     */
    get talks(): TalksClient;
    get clips(): ClipsClient;
}
